INSERT INTO `government_services` VALUES (1,'청년어촌정착지원','만 40세 미만 어업경영 3년 이하의 수산업 경영인(예정자 포함)에게 월 최대 110만원 지원 ','해양수산부','40세 미만 어업경영 3년 이하까지 신청','https://www.gov.kr/portal/rcvfvrSvc/dtlEx/119200000174','시군구청에 방문하여 신청','청년어촌정착지원 사업신청서, 사업계획서, 개인정보 동의서: https://www.sealife.go.kr/policy/policy2.do#   가족관계증명서: https://efamily.scourt.go.kr/index.jsp  수산업 관련 서류: https://www.naqs.go.kr/hp/contents/contents.do?menuId=MN40248&menuTypeStvl=CON&upMenuId=MN20368&hghrkMenuId=MN10003&gnrlzGroupLevelStvl=03051010000000&bbsSn=0&menuNm=%EB%86%8D%EC%97%85%EA%B2%BD%EC%98%81%EC%B2%B4+%EB%93%B1%EB%A1%9D&upMenuTypeCd=DIR&tmptNm=defaultContents&cssStvl= 수산업 관련 교육 이수증 : https://www.sealife.go.kr/ ','생활지원','18,40','.','.','.','.',NULL,NULL),(2,'자산형성지원사업(청년내일저축계좌)','기준 중위소득 50% 이하 가구의 저소득 근로청년 대상 본인적립금(월10~50만원)에 정부지원금(30만원) 매칭하여 지급- 지원내용: 본인저축액(월10~50만원) 대비 1:3 정부매칭 지원','보건복지부','2026.05.04~2026.05.20','https://www.gov.kr/portal/rcvfvrSvc/dtlEx/135200005013','https://www.bokjiro.go.kr/ssis-tbu/twataa/wlfareInfo/moveTWAT52011M.do?wlfareInfoId=WLF00000100','.','금융','15,39','기준 중위소득 50% 이하','.','.','.',NULL,NULL),(3,'청년 문화예술패스','청년의 공연·전시·영화 관람비 지원    -  공연(연극, 뮤지컬, 클래식, 오페라, 발레, 무용, 국악, 음악 콘서트, 페스티벌 등), 전시, 영화','문화체육관광부','2026.02.25.~2026.06.30.','https://www.gov.kr/portal/rcvfvrSvc/dtlEx/137100000239','https://youthculturepass.or.kr/','.','문화/예술','19,20','.','.','.','.',NULL,NULL),(4,'청년전용창업자금','1. 시설자금    - 생산, 정보화 촉진, 유통 및 물류, 생산환경 개선 등에 필요한 기계장비의 구입에 필요한 자금    - 자가 사업장 확보를 위한 토지 구입비 및 건축 자금      * 범위 : 사업장(공장) 내 기숙사 등 복리후생 관련 복지시설 포함      * 토지구입비는 건축허가가 확정된 사업용 부지 및 산업단지 등 계획입지의 입주계약자 중 6개월 이내 건축착공이 가능한 경우에 한함    - 자가 사업장 확보를 위한 사업장 매입 자금(경,공매 포함)      * 자가 사업장 확보 자금은 기업당 3년 이내 1회로 지원 한정  2. 운전자금    - 원부자재 구입, 제품의 생산, 시장 개척, 기술 개발, 인건비, 임차보증금 등 기업 경영 활동에 소요되는 자금    -  약속어음 폐지 및 감축을 위해 대금 지급방식을 현급지급 방식으로 전환하는데 필요한 비용  3. 대출 금리 : 연 2.5%(고정)  4. 대출 기간     - 시설자금 : 10년 이내(거치 3년 이내 포함)     - 운전자금 : 6년 이내(거치 3년 이내 포함)  5.  대출한도 : 기업당 최대 1억원 이내       * 제조업 및 지역특화(주력)산업은 2억원 이내','중소벤처기업부','접수기관 별 상이','https://www.gov.kr/portal/rcvfvrSvc/dtlEx/142000000099','https://digital.kosmes.or.kr/dh/map/main.do?','중소기업 기업진단 및 정책자금 융자신청서: https://www.kosmes.or.kr/nsh/SH/IFS/SHIFS015F0.do?seqNo=450','창업','0,39 ','.','.','.','.',NULL,NULL),(5,'청년상인 육성 지원','청년상인의 생애주기(창업-성장-도약) 단계별 맞춤 지원    - (창업) 기초 역량 강화를 위한 밀착 컨설팅    - (성장) 실전 매출 증대를 위한 운영 역량 고도화    - (도약) 앵커점포 및 차세대 리더 육성 등 기업가형 도약 지원','중소벤처기업부','세부사업별 상이','https://www.gov.kr/portal/rcvfvrSvc/dtlEx/142100000037','https://tmdf.or.kr/sub/sub02_01.php','공고문 링크: https://www.bizinfo.go.kr/sii/siia/selectSIIA200Detail.do?pblancId=PBLN_000000000108351  주민등록등본:https://www.gov.kr/mw/AA020InfoCappView.do?CappBizCD=13100000015','창업','0,39 ','.','.','.','.',NULL,NULL),(6,'청년 일경험 지원','인턴형 일경험: 기업에서 과업을 수행하면서 직무역량 강화(1~5개월 내외)  프로젝트형 일경험: 기업이 제안하는 실전형 프로젝트 수행(2개월 내외)  ESG지원형 일경험: 청년의 취업역량 향상을 위해 기업이 ESG 경영차원에서 편성한 일경험, 직무훈련 등 참여(6개월 이내)  기업탐방형 일경험: 현직자 멘토링, CEO·인사 담당자 대화 등을 통한 진로탐색 지원(5일 내외)','고용노동부','사업공고에 따름','https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200005006','https://yw.work24.go.kr/main.do','포털 홈페이지 : https://yw.work24.go.kr/main.do 졸업 및 재학 증명서: https://www.gov.kr/mw/AA020InfoCappView.do?HighCtgCD=&CappBizCD=13404000010','취업','15,34','.','.','.','.',NULL,NULL),(7,'청년일자리도약장려금','유형1    - 취업애로청년을 정규직으로 채용하고 6개월 이상 고용유지 시 기업에 1년간 최대 720만원 지원  유형2  - 빈일자리 업종의 우선지원대상기업에서 청년을 정규직으로 채용 후 6개월 이상 고용유지시 최장 1년간 최대 720만원 지원  - 해당 빈일자리 기업에서 18개월 이상 재직한 청년에게 최대 480만원을 지원','고용노동부','2025-01-01~2025-12-31','https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200005016','https://www.work24.go.kr/wk/k/a/1430/operOrgList.do','청년일자리도약장려금 사업 참여 신청서  : https://www.work24.go.kr/cm/c/b/1100/selectBbttInfo.do?currentPageNo=2&recordCountPerPage=10&sortTycd=1&searchTxt=%EC%B2%AD%EB%85%84%EC%9D%BC%EC%9E%90%EB%A6%AC%EB%8F%84%EC%95%BD%EC%9E%A5%EB%A0%A4%EA%B8%88&searchTycd=1&polySvcFomtId=FM00000762  , 개인정보 동의서(사업주용) : https://www.work24.go.kr/cm/c/b/1100/selectBbttInfo.do?currentPageNo=2&recordCountPerPage=10&polySvcFomtId=FM0000076  ,    개인정보 동의서(근로자용): https://www.work24.go.kr/cm/c/b/1100/selectBbttInfo.do?currentPageNo=2&recordCountPerPage=10&sortTycd=1&searchTxt=%EB%8F%99%EC%9D%98%EC%84%9C&searchTycd=1&polySvcFomtId=FM00000771 ,  중소기업 지원사업 통합관리시스템 정보 활용을 위한 동의서: https://www.work24.go.kr/cm/c/b/1100/selectBbttInfo.do?currentPageNo=1&recordCountPerPage=10&sortTycd=1&searchTxt=%EC%A4%91%EC%86%8C%EA%B8%B0%EC%97%85+%EC%A7%80%EC%9B%90%EC%82%AC%EC%97%85+%ED%86%B5%ED%95%A9%EA%B4%80%EB%A6%AC%EC%8B%9C%EC%8A%A4%ED%85%9C+%EC%A0%95%EB%B3%B4+%ED%99%9C%EC%9A%A9%EC%9D%84+%EC%9C%84%ED%95%9C+%EB%8F%99%EC%9D%98%EC%84%9C&searchTycd=1&polySvcFomtId=FM00000766 ,  https://www.work24.go.kr/cm/c/b/1100/selectBbttInfo.do currentPageNo=1&recordCountPerPage=10&sortTycd=1&searchTxt=%EC%B5%9C%EC%A2%85+%ED%95%99%EB%A0%A5%EC%97%90+%EB%8C%80%ED%95%9C+%EC%9E%90%EA%B8%B0+%ED%99%95%EC%9D%B8%EC%84%9C&searchTycd=1&polySvcFomtId=FM00000770','취업','15,34','.','.','.','.',NULL,NULL),(8,'청년 국가기술자격시험 응시료 지원','만34세 이하 청년을 대상으로 한국산업인력공단이 시행하는 국가기술자격 시험(24년 기준 493 종목)에 응시하는 경우 응시료의 50%를 선 지원(종목 선택 후 감면된 금액으로 결제)    -  1인당 총 3회 지원, 지원금 소진 시까지','고용노동부','상시신청','https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200005023','https://www.q-net.or.kr/rcv001.do?id=rcv00103&gSite=Q&gId=','.','교육','0,34','.','.','.','.',NULL,NULL),(9,'청년도전지원사업 안내','구직단념청년 등을 대상으로 밀착상담, 사례관리, 자신감회복, 진로탐색, 취업역량강화 등 맞춤형 프로그램 및   참여수당, 인센티브 등을 제공하여 청년의 구직의욕 고취, 노동시장 참여 및 취업 촉진 지원   1단계) 구직단념청년 등 참여자 발굴·모집 →   (2단계) 사회활동 참여의욕 고취를 위한 맞춤형 프로그램 제공 →   (3단계) 이수 시 국민취업지원제도·일경험·직업훈련 등 연계                        취업 시 고용촉진장려금 등 연계','고용노동부','상시신청','https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200005033','https://www.work24.go.kr/cm/main.do','.','취업','18,34','.','.','.','.',NULL,NULL),(10,'청년농업인 영농정착지원','선발인원에 대해 정착지원금(월 최대 110만원), 농신보 우대보증, 농지임대 우선지원 및 영농기술 교육 등 패키지 지원','농림축산식품부','지자체(시, 군, 구) 공고','https://www.gov.kr/portal/rcvfvrSvc/dtlEx/154300000396','https://www.nongupez.go.kr/nsm/main','https://www.naqs.go.kr/hp/contents/contents.do?menuId=MN40248&menuTypeStvl=CON&upMenuId=MN20368&hghrkMenuId=MN10003&gnrlzG